class BIT {
    int[] tree;
    int size;

    public BIT(int size) {
        this.size = size;
        tree = new int[size + 1];
    }

    public void update(int index, int delta) {
        while (index <= size) {
            tree[index] += delta;
            index += index & -index;
        }
    }

    public int query(int index) {
        int res = 0;
        while (index > 0) {
            res += tree[index];
            index -= index & -index;
        }
        return res;
    }
}

class Solution {
    public int[] popcountDepth(long[] nums, long[][] queries) {
        int n = nums.length;
        int[] depths = new int[n];
        for (int i = 0; i < n; i++) {
            depths[i] = getDepth(nums[i]);
        }

        BIT[] bits = new BIT[5];
        for (int d = 0; d < 5; d++) {
            bits[d] = new BIT(n);
        }

        for (int i = 0; i < n; i++) {
            int d = depths[i];
            bits[d].update(i + 1, 1);
        }

        List<Integer> result = new ArrayList<>();

        for (long[] query : queries) {
            if (query[0] == 1) {
                int l = (int) query[1];
                int r = (int) query[2];
                int k = (int) query[3];
                int count = bits[k].query(r + 1) - bits[k].query(l);
                result.add(count);
            } else {
                int idx = (int) query[1];
                long val = query[2];
                int oldD = depths[idx];
                bits[oldD].update(idx + 1, -1);
                int newD = getDepth(val);
                depths[idx] = newD;
                bits[newD].update(idx + 1, 1);
            }
        }

        int[] res = new int[result.size()];
        for (int i = 0; i < res.length; i++) {
            res[i] = result.get(i);
        }
        return res;
    }

    private static int getDepth(long x) {
        if (x == 1) return 0;
        int depth = 0;
        while (x != 1) {
            x = Long.bitCount(x);
            depth++;
        }
        return depth;
    }
}

